const gh = $input.first().json;
let jobs = [];
try {
  const db = JSON.parse(Buffer.from(gh.content, 'base64').toString('utf-8'));
  jobs = db.jobs || [];
} catch(e) { console.log('Jobs load error:', e.message); }

const today   = new Date().toISOString().slice(0, 10);
const sorted  = [...jobs].sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0));
const top5    = sorted.slice(0, 5);
const interns = jobs
  .filter(j => j.job_type === 'internship')
  .sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0))
  .slice(0, 3);
const remote  = jobs
  .filter(j => /remote/i.test(j.location || ''))
  .sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0))
  .slice(0, 3);
const avg     = jobs.length
  ? (jobs.reduce((s, j) => s + (j.relevance_score || 0), 0) / jobs.length).toFixed(1) : 0;
const newToday = jobs.filter(j => j.date_found && j.date_found.startsWith(today)).length;

return [{ json: { total: jobs.length, new_today: newToday, top5, interns, remote, avg } }];

const items = $input.all();
if (!items.length) {
  console.log('IMAP: no emails — nothing to process');
  return [{ json: { action: 'NONE', message: 'Inbox empty' } }];
}
const commands = [];
items.forEach(item => {
  const rawBody = item.json.text || item.json.textHtml || item.json.html || '';
  const body    = rawBody.replace(/<[^>]+>/g, '');
  const subj    = item.json.subject || '';
  const full    = subj + '\n' + body;
  // Match job_id format: j_ followed by exactly 16 hex characters
  const apMatch  = full.match(/APPROVE\s+(j_[0-9a-f]{16})/i);
  const rejMatch = full.match(/REJECT\s+(j_[0-9a-f]{16})/i);
  if (apMatch)  commands.push({ action: 'APPROVE', job_id: apMatch[1].toLowerCase() });
  if (rejMatch) commands.push({ action: 'REJECT',  job_id: rejMatch[1].toLowerCase() });
});
if (!commands.length) {
  console.log('IMAP: ' + items.length + ' email(s) but no valid APPROVE/REJECT commands');
  return [{ json: { action: 'NONE', message: 'No commands in ' + items.length + ' emails' } }];
}
console.log('Commands found: ' + commands.length);
return commands.map(c => ({ json: c }));

const all      = $input.all();
// Identify inputs by filename in GitHub API response 'name' field
const resumeGH = all.find(i => i.json.name && i.json.name.endsWith('_resume.txt'));
const atsGH    = all.find(i => i.json.name && i.json.name.endsWith('_ats_report.json'));

let resumeText = '(Resume not found — verify Agent 2 ran today and job was in top 5)';
let ats = { ats_score: 65, job_title: 'the role', company: 'the company',
  job_url: '', hiring_potential: 60, recommendation: 'good_fit',
  strengths: [], improvements: [] };
// FIX: extract job_id from GitHub response filename — matches exactly what Agent 2 stored
let jobId = 'unknown';

if (resumeGH) {
  try { resumeText = Buffer.from(resumeGH.json.content, 'base64').toString('utf-8'); }
  catch(e) { console.log('Resume decode error:', e.message); }
  jobId = (resumeGH.json.name || '').replace('_resume.txt', '');
}
if (atsGH) {
  try { ats = JSON.parse(Buffer.from(atsGH.json.content, 'base64').toString('utf-8')); }
  catch(e) { console.log('ATS decode error:', e.message); }
}

const { job_title, company, job_url, ats_score, hiring_potential,
        recommendation, strengths, improvements } = ats;
const scoreColor = ats_score >= 75 ? '#059669' : ats_score >= 60 ? '#d97706' : '#dc2626';

const html =
  '<!DOCTYPE html><html><body style="font-family:-apple-system,BlinkMacSystemFont,' +
    'Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;">' +
  '<div style="background:' + scoreColor + ';color:#fff;padding:24px;border-radius:8px;' +
    'text-align:center;margin-bottom:20px;">' +
    '<div style="font-size:36px;">&#9989;</div>' +
    '<div style="font-size:20px;font-weight:700;margin-top:8px;">Resume Ready!</div>' +
    '<div style="font-size:14px;opacity:.9;margin-top:4px;">' + job_title + ' at ' + company + '</div>' +
  '</div>' +
  '<div style="background:#f8fafc;border-radius:8px;padding:16px;margin-bottom:16px;' +
    'display:flex;justify-content:space-around;text-align:center;">' +
    '<div><div style="font-size:30px;font-weight:700;color:#0f172a;">' + (ats_score || 65) + '</div>' +
      '<div style="font-size:10px;color:#64748b;text-transform:uppercase;">ATS Score</div></div>' +
    '<div><div style="font-size:30px;font-weight:700;color:#0ea5e9;">' + (hiring_potential || 60) + '</div>' +
      '<div style="font-size:10px;color:#64748b;text-transform:uppercase;">Match %</div></div>' +
    '<div style="padding-top:6px;">' +
      '<div style="font-size:12px;font-weight:700;color:' + scoreColor + ';">' +
        (recommendation || 'good_fit').replace(/_/g, ' ').toUpperCase() + '</div>' +
      '<div style="font-size:10px;color:#64748b;text-transform:uppercase;">Verdict</div></div>' +
  '</div>' +
  (strengths && strengths.length ?
    '<div style="margin-bottom:14px;"><strong>&#10003; Strengths</strong>' +
    '<ul style="margin:6px 0;padding-left:18px;color:#374151;">' +
    strengths.map(s => '<li style="margin:3px 0;font-size:13px;">' + s + '</li>').join('') +
    '</ul></div>' : '') +
  (improvements && improvements.length ?
    '<div style="margin-bottom:18px;"><strong>&#128161; Application Tips</strong>' +
    '<ul style="margin:6px 0;padding-left:18px;color:#374151;">' +
    improvements.map(s => '<li style="margin:3px 0;font-size:13px;">' + s + '</li>').join('') +
    '</ul></div>' : '') +
  (job_url ? '<div style="text-align:center;margin:20px 0;">' +
    '<a href="' + job_url + '" style="background:#0ea5e9;color:#fff;padding:13px 28px;' +
      'border-radius:6px;text-decoration:none;font-weight:600;font-size:14px;">Apply Now &rarr;</a>' +
    '</div>' : '') +
  '<div style="background:#f1f5f9;padding:14px;border-radius:6px;font-size:13px;color:#475569;">' +
    '&#128204; Resume attached as <strong>' + jobId + '_resume.txt</strong>. ' +
    'Copy-paste into application forms for best ATS results.' +
  '</div>' +
  '<div style="text-align:center;margin-top:20px;font-size:11px;color:#94a3b8;">' +
    'AI Job Intelligence &bull; &#128640;' +
  '</div></body></html>';

return [{ json: {
  html, resumeText, job_id: jobId, job_title, company,
  ats_score: ats_score || 65,
  subject: '\u2705 Resume Ready \u2014 ' + job_title +
    ' @ ' + company + ' (ATS: ' + (ats_score || 65) + '/100)',
  filename: jobId + '_approval.json'
} }];

const d = $input.first().json;
const record = { job_id: d.job_id, status: 'approved',
  ats_score: d.ats_score, job_title: d.job_title,
  company: d.company, ts: new Date().toISOString() };
return [{ json: {
  github_payload: {
    message: 'auto: approved ' + d.job_id,
    content: Buffer.from(JSON.stringify(record, null, 2)).toString('base64'),
    branch: 'state'
    // No sha — new file per approval, no SHA conflict possible
  },
  filename: d.filename,
  job_id:   d.job_id
} }];

const d = $input.first().json;
console.log('=== AGENT 3b: APPROVAL COMPLETE ===');
console.log('Job ID: ' + d.job_id);
console.log('Status file: data/approvals/' + d.job_id + '_approval.json');
return [{ json: { status: 'approved', job_id: d.job_id, ts: new Date().toISOString() } }];
